        href: "/developer/sdk",
        icon: (
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
          </svg>
        ),
      },
    ],
  },
  {
    label: "Resources",
    items: [
      {
        label: "Documentation",
        desc: "Guides and API references.",
        href: "/docs",
        icon: (
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
          </svg>
        ),
      },
      {
        label: "Changelogs",
        desc: "Latest updates and improvements.",
        href: "/changelogs",
        icon: (
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        ),
      },
    ],
  },
  { label: "Download", href: "/download" },
];

export function Navbar() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [openAccordion, setOpenAccordion] = useState<string | null>(null);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      // Increased threshold to 80px so it triggers later
      setIsScrolled(window.scrollY > 80);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();

    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const toggleAccordion = (label: string) => {
    setOpenAccordion(openAccordion === label ? null : label);
  };

  return (
    <header
      className="fixed top-0 left-0 right-0 z-50 transition-all duration-300"
      style={{
        background: "rgba(14, 14, 13, 0.70)",
        backdropFilter: "blur(20px) saturate(180%)",
        WebkitBackdropFilter: "blur(20px) saturate(180%)",
        boxShadow: "0 0 0 1px rgba(226, 226, 226, 0.06)",
      }}
    >
      <nav className="w-full max-w-7xl mx-auto px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Logo — left */}
          <Link href="/" className="flex items-center group flex-shrink-0">
            <img
              src="/logo.svg"
              alt="Gunmetal"
              className="h-8 w-auto flex-shrink-0 relative z-10 bg-transparent"
              style={{ display: "block" }}
            />
            {/* 
              The container forms a hard mask perfectly adjacent to the logo. 
              We translate the text *inside* the container rather than translating the container, 
              ensuring the text gets clipped right at the container's left edge instead of sliding behind the transparent logo.
            */}
            <div
              className={`overflow-hidden transition-all duration-700 ease-[cubic-bezier(0.25,1,0.5,1)] ml-2.5 ${
                isScrolled ? "max-w-0 opacity-0" : "max-w-[150px] opacity-100"
              }`}
            >
              <span
                className={`block text-[20px] tracking-tight text-[var(--text)] whitespace-nowrap transition-transform duration-700 ease-[cubic-bezier(0.25,1,0.5,1)] ${
                  isScrolled ? "-translate-x-full" : "translate-x-0"
                }`}
                style={{ fontFamily: "var(--font-matter)", fontWeight: 500 }}
              >
                Gunmetal
              </span>
            </div>
          </Link>

          {/* Nav links + GitHub — right side, tight grouping */}
          <div className="hidden lg:flex items-center gap-6">
            {navItems.map((item) => (
