                      fill="none"
                      viewBox="0 0 24 24"
                      stroke="currentColor"
                      strokeWidth={2}
                    >
                      <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>
                ) : (
                  <Link
                    href={item.href!}
                    className="flex items-center text-[15px] text-[var(--text-muted)] hover:text-[var(--text)] transition-colors duration-200 py-5"
                    style={{ fontFamily: "var(--font-matter)", fontWeight: 400 }}
                  >
                    {item.label}
                  </Link>
                )}

                {/* Dropdown Menu - Expanded, Designed, Smooth */}
                {item.items && (
                  <div className="absolute top-[calc(100%-0.5rem)] left-1/2 -translate-x-1/2 pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-300 transform translate-y-3 group-hover:translate-y-0 z-50">
                    <div
                      className="rounded-xl p-2 min-w-[280px] grid gap-1"
                      style={{
                        background: "rgba(14, 14, 13, 0.85)",
                        backdropFilter: "blur(24px) saturate(200%)",
                        boxShadow: "0 10px 40px -10px rgba(0,0,0,0.7), 0 0 0 1px rgba(226, 226, 226, 0.1)",
                      }}
                    >
                      {item.items.map((subItem) => (
                        <Link
                          key={subItem.href}
                          href={subItem.href}
                          className="group/item flex items-start gap-3 p-3 text-[var(--text-muted)] hover:text-[var(--text)] hover:bg-[var(--frosted)] rounded-lg transition-all duration-200"
                        >
                          <div className="shrink-0 text-[var(--text-muted)] group-hover/item:text-[var(--text)] transition-colors duration-200 mt-0.5">
                            {subItem.icon}
                          </div>
                          <div className="flex flex-col">
                            <span
                              className="text-[15px] font-medium text-[var(--text)] transition-colors duration-200"
                              style={{ fontFamily: "var(--font-matter)" }}
                            >
                              {subItem.label}
                            </span>
                            <span className="text-[13px] text-[var(--text-muted)] mt-0.5 leading-snug">
                              {subItem.desc}
                            </span>
                          </div>
                        </Link>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ))}

            {/* GitHub */}
            <a
              href="https://github.com/Dhruv2mars/gunmetal"
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center justify-center w-8 h-8 rounded-lg text-[var(--text-muted)] hover:text-[var(--text)] hover:bg-[var(--frosted)] transition-colors duration-200 flex-shrink-0 ml-2"
              aria-label="GitHub"
