            <div
              className={`overflow-hidden transition-all duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] flex items-center ${
                isScrolled ? "max-w-0 opacity-0 -translate-x-full" : "max-w-[100px] opacity-100 translate-x-0"
              }`}
            >
              <span
                className="text-base text-[var(--text)] whitespace-nowrap pl-2.5"
                style={{ fontFamily: "var(--font-matter)", fontWeight: 400 }}
              >
                Gunmetal
              </span>
            </div>
          </Link>

          {/* Nav links + GitHub — right side, tight grouping */}
          <div className="hidden lg:flex items-center gap-6">
            {navItems.map((item) => (
              <div key={item.label} className="relative group">
                {item.items ? (
                  <button
                    className="flex items-center gap-1.5 text-base text-[var(--text-muted)] hover:text-[var(--text)] transition-colors duration-150 py-4"
                    style={{ fontFamily: "var(--font-matter)", fontWeight: 400 }}
                  >
                    {item.label}
                    <svg
                      className="w-3.5 h-3.5 text-[var(--text-muted)] group-hover:text-[var(--text)] transition-transform duration-200 group-hover:rotate-180"
                      fill="none"
                      viewBox="0 0 24 24"
                      stroke="currentColor"
                      strokeWidth={2}
                    >
                      <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                    </svg>
                  </button>
                ) : (
                  <Link
                    href={item.href!}
                    className="flex items-center text-base text-[var(--text-muted)] hover:text-[var(--text)] transition-colors duration-150 py-4"
                    style={{ fontFamily: "var(--font-matter)", fontWeight: 400 }}
                  >
                    {item.label}
                  </Link>
                )}

                {/* Dropdown Menu */}
                {item.items && (
                  <div className="absolute top-full left-1/2 -translate-x-1/2 pt-1 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 transform translate-y-2 group-hover:translate-y-0 min-w-[180px]">
                    <div
                      className="rounded-[var(--radius-sm)] p-1.5 flex flex-col gap-1"
                      style={{
                        background: "rgba(14, 14, 13, 0.95)",
                        backdropFilter: "blur(20px) saturate(180%)",
                        boxShadow: "0 4px 24px -4px rgba(0,0,0,0.5), 0 0 0 1px rgba(226, 226, 226, 0.1)",
                      }}
                    >
                      {item.items.map((subItem) => (
                        <Link
                          key={subItem.href}
                          href={subItem.href}
                          className="px-3 py-2 text-sm text-[var(--text-muted)] hover:text-[var(--text)] hover:bg-[var(--frosted)] rounded-[var(--radius-xs)] transition-colors duration-150 whitespace-nowrap"
                          style={{ fontFamily: "var(--font-matter)", fontWeight: 400 }}
                        >
                          {subItem.label}
                        </Link>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ))}

            {/* GitHub — match logo height, muted color */}
            <a
              href="https://github.com/Dhruv2mars/gunmetal"
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center justify-center w-7 h-7 rounded-[var(--radius-xs)] text-[var(--text-muted)] hover:text-[var(--text)] transition-colors duration-150 flex-shrink-0 ml-2"
              aria-label="GitHub"
            >
              <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24">
                <path
                  fillRule="evenodd"
                  clipRule="evenodd"
