                />
              </svg>
            </a>
          </div>

          {/* Mobile Right Section */}
          <div className="lg:hidden flex items-center gap-3">
            <a
              href="https://github.com/Dhruv2mars/gunmetal"
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center justify-center w-8 h-8 rounded-[var(--radius-xs)] text-[var(--text-muted)] hover:text-[var(--text)] transition-colors duration-150 flex-shrink-0"
              aria-label="GitHub"
            >
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                <path
                  fillRule="evenodd"
                  clipRule="evenodd"
