                {item.items ? (
                  <>
                    <button
                      onClick={() => toggleAccordion(item.label)}
                      className="flex items-center justify-between w-full px-4 py-3 text-base text-[var(--text)] hover:bg-[var(--frosted)] rounded-[var(--radius-sm)] transition-colors duration-150"
                      style={{ fontFamily: "var(--font-matter)", fontWeight: 400 }}
                    >
                      {item.label}
                      <svg
                        className={`w-4 h-4 text-[var(--text-muted)] transition-transform duration-200 ${
                          openAccordion === item.label ? "rotate-180" : ""
